374	// SynthesizeCommit stages real file changes, explicitly excluding harness noise
375	// paths, and creates a commit with msg as the commit message. Returns (true, nil)
376	// when a commit was made, (false, nil) when nothing real remained to commit
377	// after exclusions, and (false, err) on failure.
378	func (r *RealGitOps) SynthesizeCommit(dir, msg string) (bool, error) {
379		// Do NOT list already-gitignored paths (.ddx/agent-logs, .ddx/workers) as
380		// :(exclude) pathspecs. Git treats a path named by :(exclude) as explicitly
381		// referenced, so when the path is also .gitignored git emits "The following
382		// paths are ignored by one of your .gitignore files" AND exits 1 — even
383		// though the pathspec is trying to SKIP it. Paths already in .gitignore are
384		// excluded by default; excludes here are only for paths that would
385		// otherwise be tracked.
386		addArgs := []string{
387			"add", "-A", "--",
388			".",
389		}
390		addArgs = append(addArgs, synthesizeCommitExcludePathspecs(dir)...)
391		if err := internalgit.Command(context.Background(), dir, addArgs...).Run(); err != nil {
392			return false, fmt.Errorf("staging changes: %w", err)
393		}
394		statusOut, _ := internalgit.Command(context.Background(), dir, "diff", "--cached", "--name-only").Output()
395		if len(bytes.TrimSpace(statusOut)) == 0 {
396			return false, nil
397		}
398		if msg == "" {
399			msg = "chore: execute-bead synthesized result commit"
400		}
401		out, err := internalgit.Command(context.Background(), dir, "commit", "-m", msg).CombinedOutput()
402		if err != nil {
403			return false, fmt.Errorf("synthesize commit: %s: %w", strings.TrimSpace(string(out)), err)
404		}
405		return true, nil
406	}
