408	func synthesizeCommitExcludePathspecs(dir string) []string {
409		candidates := []struct {
410			pathspec    string
411			ignoreProbe string
412		}{
413			{
414				pathspec:    ":(exclude).ddx/executions/*/embedded",
415				ignoreProbe: ".ddx/executions/.ddx-check-ignore/embedded",
416			},
417			{
418				pathspec:    ":(exclude).ddx/executions/*/no_changes_rationale.txt",
419				ignoreProbe: ".ddx/executions/.ddx-check-ignore/no_changes_rationale.txt",
420			},
421			{
422				pathspec:    ":(exclude).claude/skills",
423				ignoreProbe: ".claude/skills",
424			},
425			{
426				pathspec:    ":(exclude).agents/skills",
427				ignoreProbe: ".agents/skills",
428			},
429		}
430	
431		pathspecs := make([]string, 0, len(candidates))
432		for _, c := range candidates {
433			if isGitIgnored(dir, c.ignoreProbe) {
434				continue
435			}
436			pathspecs = append(pathspecs, c.pathspec)
437		}
438		return pathspecs
439	}
