347	// harness and translates the result into a ProviderStatus. It is the
348	// production replacement for Runner.TestProviderConnectivity.
349	func TestProviderConnectivityViaService(ctx context.Context, workDir, harnessName string, timeout time.Duration) ProviderStatus {
350		status := ProviderStatus{Reachable: false}
351		if ctx == nil {
352			ctx = context.Background()
353		}
354		if harnessName == "virtual" || harnessName == "agent" {
355			status.Reachable = true
356			status.CreditsOK = true
357			return status
358		}
359		svc, err := NewServiceFromWorkDir(workDir)
360		if err != nil {
361			status.Error = err.Error()
362			return status
363		}
364		if timeout > 0 {
365			var cancel context.CancelFunc
366			ctx, cancel = context.WithTimeout(ctx, timeout)
367			defer cancel()
368		}
369		if err := svc.HealthCheck(ctx, agentlib.HealthTarget{Type: "harness", Name: harnessName}); err != nil {
370			errStr := strings.ToLower(err.Error())
371			status.Error = err.Error()
372			if strings.Contains(errStr, "429") || strings.Contains(errStr, "quota") ||
373				strings.Contains(errStr, "credit") || strings.Contains(errStr, "insufficient") {
374				status.CreditsOK = false
375			}
376			return status
377		}
378		status.Reachable = true
379		status.CreditsOK = true
380		return status
381	}
