1985			fmt.Fprintln(cmd.OutOrStdout(), "No execution-ready beads.")
1986			d := result.NoReadyWorkDetail
1987			if len(d.SkippedEpics) > 0 {
1988				fmt.Fprintf(cmd.OutOrStdout(), "  skipped %d ready epic(s) (epics are structural containers; decompose into tasks): %s\n",
1989					len(d.SkippedEpics), strings.Join(d.SkippedEpics, ", "))
1990			}
1991			if len(d.SkippedOnCooldown) > 0 {
1992				retryHint := ""
1993				if d.NextRetryAfter != "" {
1994					retryHint = " (next retry-after: " + d.NextRetryAfter + ")"
1995				}
1996				fmt.Fprintf(cmd.OutOrStdout(), "  skipped %d bead(s) on retry cooldown%s: %s\n",
1997					len(d.SkippedOnCooldown), retryHint, strings.Join(d.SkippedOnCooldown, ", "))
1998			}
1999			if len(d.SkippedNotEligible) > 0 {
2000				fmt.Fprintf(cmd.OutOrStdout(), "  skipped %d bead(s) with execution-eligible=false: %s\n",
2001					len(d.SkippedNotEligible), strings.Join(d.SkippedNotEligible, ", "))
2002			}
2003			if len(d.SkippedSuperseded) > 0 {
2004				fmt.Fprintf(cmd.OutOrStdout(), "  skipped %d superseded bead(s): %s\n",
2005					len(d.SkippedSuperseded), strings.Join(d.SkippedSuperseded, ", "))
2006			}
2007			return nil
2008		}
2009	
2010		fmt.Fprintf(cmd.OutOrStdout(), "\nproject: %s\n", projectRoot)
2011		fmt.Fprintf(cmd.OutOrStdout(), "completed: %d  |  successes: %d  |  failures: %d\n", result.Attempts, result.Successes, result.Failures)
2012		if result.Failures > 0 {
2013			fmt.Fprintf(cmd.OutOrStdout(), "\nfailed:\n")
2014			for _, attempt := range result.Results {
2015				if attempt.Status != "success" {
2016					fmt.Fprintf(cmd.OutOrStdout(), "  - %s: %s", attempt.BeadID, attempt.Detail)
2017					if attempt.PreserveRef != "" {
2018						fmt.Fprintf(cmd.OutOrStdout(), " (preserved)")
2019					}
2020					fmt.Fprintln(cmd.OutOrStdout())
2021				}
2022			}
2023		}
2024		return nil
