98	// resolvedWithPassthrough builds a sealed ResolvedConfig with the given
99	// harness/provider/model/minPower/maxPower and no other overrides.
100	func resolvedWithPassthrough(harness, provider, model string, minPower, maxPower int) config.ResolvedConfig {
101		cfg := config.NewTestConfigForRun(config.TestRunConfigOpts{
102			Harness: harness,
103			Model:   model,
104		})
105		return cfg.Resolve(config.CLIOverrides{
106			Provider: provider,
107			MinPower: minPower,
108			MaxPower: maxPower,
109		})
110	}
