112	// TestPassthroughEnvelope_InvariantUnderPowerEscalation (AC3): bumping MinPower
113	// does not mutate harness/provider/model in the passthrough.
114	func TestPassthroughEnvelope_InvariantUnderPowerEscalation(t *testing.T) {
115		rcfg := resolvedWithPassthrough("claude", "anthropic", "claude-3-5-sonnet", 0, 0)
116		pt := rcfg.Passthrough()
117	
118		// Simulate retry escalation: produce a new ResolvedConfig with higher MinPower
119		// but the same harness/provider/model. The passthrough must stay the same.
120		escalated := resolvedWithPassthrough("claude", "anthropic", "claude-3-5-sonnet", 50, 100)
121		ptEscalated := escalated.Passthrough()
122	
123		if ptEscalated.Harness != pt.Harness {
124			t.Errorf("Harness changed under escalation: got %q, want %q", ptEscalated.Harness, pt.Harness)
125		}
126		if ptEscalated.Provider != pt.Provider {
127			t.Errorf("Provider changed under escalation: got %q, want %q", ptEscalated.Provider, pt.Provider)
128		}
129		if ptEscalated.Model != pt.Model {
130			t.Errorf("Model changed under escalation: got %q, want %q", ptEscalated.Model, pt.Model)
131		}
132	
133		// MaxPower must be preserved too.
134		if escalated.MaxPower() != 100 {
135			t.Errorf("MaxPower should be 100 after escalation, got %d", escalated.MaxPower())
136		}
137		if escalated.MinPower() != 50 {
138			t.Errorf("MinPower should be 50 after escalation, got %d", escalated.MinPower())
139		}
140	}
