154	// TestExecuteOnService_InvalidPassthroughNotPrevalidated (AC6): DDx must NOT
155	// reject an obviously bogus harness/provider/model before forwarding to the
156	// service. The service is the authoritative validator.
157	func TestExecuteOnService_InvalidPassthroughNotPrevalidated(t *testing.T) {
158		svc := &passthroughTestService{}
159		rcfg := resolvedWithPassthrough("definitely-not-a-real-harness!!!", "bogus-provider", "bogus-model-xyz", 0, 0)
160	
161		_, err := executeOnService(context.Background(), svc, t.TempDir(), rcfg, AgentRunRuntime{
162			Prompt: "hello",
163		})
164		// DDx must not return an error from pre-validation; the service stub
165		// returns success so we expect no error here.
166		if err != nil {
167			t.Errorf("DDx pre-validated passthrough and returned error (must not): %v", err)
168		}
169		if !svc.executeCalled {
170			t.Error("Execute was never called — DDx must forward invalid passthrough to service unchanged")
171		}
172		if svc.lastReq.Harness != "definitely-not-a-real-harness!!!" {
173			t.Errorf("Harness was mutated before forwarding: got %q", svc.lastReq.Harness)
174		}
175		if svc.lastReq.Provider != "bogus-provider" {
176			t.Errorf("Provider was mutated before forwarding: got %q", svc.lastReq.Provider)
177		}
178		if svc.lastReq.Model != "bogus-model-xyz" {
179			t.Errorf("Model was mutated before forwarding: got %q", svc.lastReq.Model)
